SELECT
  (
    SELECT to_char(
      est_finish_date AT TIME ZONE '$timezone',
      'FMMM/FMDD FMHH12:MI AM'
    )
    FROM runners
    LIMIT 1
  ) AS est_finish_date,
  COALESCE(
    (SELECT est_finish_time FROM runners LIMIT 1),
    0.0
  ) AS est_finish_time;

SELECT NULLIF(last_update, '1970-01-01 00:00:00') AS from_now
FROM runners
LIMIT 1;

SELECT COALESCE(
  (SELECT elapsed_time FROM runners LIMIT 1),
  0.0 
) AS elapsed_time;

SELECT COALESCE(
  (SELECT moving_time FROM runners LIMIT 1),
  0.0 
) AS moving_time;

SELECT COALESCE(
  (SELECT stoppage_time FROM runners LIMIT 1),
  0.0 
) AS stoppage_time;
